func autoMigrateAll(db *gorm.DB) error {
	models := []interface{}{
		&model.User{},
		&model.Forward{},
		&model.ForwardPort{},
		&model.Node{},
		&model.SpeedLimit{},
		&model.StatisticsFlow{},
		&model.Tunnel{},
