		&model.PeerShare{},
		&model.PeerShareRuntime{},
		&model.FederationTunnelBinding{},
		&model.Announcement{},
		&model.SchemaVersion{},
	}

	if db.Dialector.Name() != "sqlite" {
		return db.AutoMigrate(models...)
	}

	m := db.Migrator()
	hasNode := m.HasTable(&model.Node{})
	hasTunnel := m.HasTable(&model.Tunnel{})

	for _, item := range models {
