			InFlow:        u.InFlow,
			OutFlow:       u.OutFlow,
			FlowResetTime: u.FlowResetTime,
			Num:           u.Num,
			CreatedTime:   u.CreatedTime,
			UpdatedTime:   sql.NullInt64{Int64: now, Valid: true},
			Status:        u.Status,
		}
		err := tx.Clauses(clause.OnConflict{
			Columns: []clause.Column{{Name: "id"}},
