	columns := readTableColumns(t, r.DB(), "node")

	for _, required := range []string{"server_ip_v4", "server_ip_v6", "inx", "extra_ips"} {
		if !columns[required] {
			t.Fatalf("expected node column %q to exist after migration", required)
